import math


def area_of_circle(radius):
    """<codehere>"""
    return math.pi * radius ** 2
    """</codehere>"""


"""<comment>"""
# This cell is for grading, do not modify
assert area_of_circle(1) == math.pi
"""</comment>"""


def perimeter(radius):
    """<codehere>"""
    return 2 * math.pi * radius
    """</codehere>"""
